using System;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var build = BinaryLog.ReadBuild(args[0]);

Console.WriteLine("========== ALL ERRORS ==========");
var errors = build.FindChildrenRecursive<Error>();
foreach (var e in errors)
{
    Console.WriteLine($"[{e.File}({e.LineNumber},{e.ColumnNumber})] {e.Code}: {e.Text}");
    var node = (BaseNode)e.Parent;
    while (node != null && node is not Project)
        node = (BaseNode)node.Parent;
    if (node is Project p)
        Console.WriteLine($"  -> In project: {p.Name} | Target: {e.Parent}");
    Console.WriteLine();
}

Console.WriteLine("\n========== BUILD RESULT PER PROJECT ==========");
var projects = build.FindChildrenRecursive<Project>();
// Deduplicate by project file path and show build targets
foreach (var p in projects)
{
    var projectErrors = p.FindChildrenRecursive<Error>();
    var hasErrors = projectErrors.Any();
    Console.WriteLine($"Project: {p.Name} | SourceFilePath: {p.SourceFilePath} | HasErrors: {hasErrors}");
    if (hasErrors)
    {
        foreach (var e in projectErrors)
            Console.WriteLine($"  ERROR: {e.Code}: {e.Text}");
    }
}

Console.WriteLine("\n========== DEPENDENCY CHAIN ==========");
// Check if Api had dependency failures
var buildMessages = build.FindChildrenRecursive<Message>();
foreach (var m in buildMessages)
{
    if (m.Text != null && (m.Text.Contains("dependency") || m.Text.Contains("previously") || m.Text.Contains("did not build")))
        Console.WriteLine($"MSG: {m.Text}");
}

// Look for MSB errors
var allItems = build.FindChildrenRecursive<Item>();
Console.WriteLine($"\nTotal items: {allItems.Count()}");

// Check for project build dependency / cascading info
Console.WriteLine("\n========== TARGET FAILURES ==========");
var targets = build.FindChildrenRecursive<Target>();
foreach (var t in targets)
{
    var tErrors = t.FindChildrenRecursive<Error>();
    if (tErrors.Any())
    {
        var node = (BaseNode)t.Parent;
        while (node != null && node is not Project)
            node = (BaseNode)node.Parent;
        var projectName = node is Project pp ? pp.Name : "unknown";
        Console.WriteLine($"Target: {t.Name} in {projectName}");
        foreach (var e in tErrors)
            Console.WriteLine($"  {e.Code}: {e.Text}");
    }
}
