using System;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var build = BinaryLog.ReadBuild(args[0]);

// Check for any "skipped" or "not built" messages related to projects
Console.WriteLine("========== MESSAGES WITH PROJECT BUILD STATUS ==========");
var allMessages = build.FindChildrenRecursive<Message>();
foreach (var m in allMessages)
{
    if (m.Text != null && (
        m.Text.Contains("not building") || 
        m.Text.Contains("was not built") ||
        m.Text.Contains("skipping") ||
        m.Text.Contains("Skipping") ||
        m.Text.Contains("previously failed") ||
        m.Text.Contains("cannot be found") ||
        m.Text.Contains("dependency \"Services")))
    {
        Console.WriteLine($"MSG: {m.Text}");
    }
}

// Show all Build targets and their success status
Console.WriteLine("\n========== BUILD TARGET RESULTS (Build/Compile targets) ==========");
var targets = build.FindChildrenRecursive<Target>();
foreach (var t in targets)
{
    if (t.Name == "CoreCompile" || t.Name == "Build" || t.Name == "ResolveProjectReferences")
    {
        var node = (BaseNode)t.Parent;
        while (node != null && node is not Project)
            node = (BaseNode)node.Parent;
        var projectName = node is Project pp ? pp.Name : "unknown";
        var hasErrors = t.FindChildrenRecursive<Error>().Any();
        Console.WriteLine($"Target: {t.Name} in {projectName} | HasErrors: {hasErrors}");
